func _process_hopping(delta: float) -> void:
	var dir: Vector3 = hop_target - global_position
	dir.y = 0
	if dir.length() > 0.8:
		dir = dir.normalized()
		velocity.x = dir.x * hop_speed
		velocity.z = dir.z * hop_speed
		_face_direction(dir, delta)
	else:
		current_state = State.IDLE
